mapper.select:
SELECT TBL.ID AS id, TBL.LOG_TITLE AS logTitle, TBL.VISION_TITLE AS visionTitle, TO_CHAR(TBL.LOG_CREATE_AT, 'YYYY.MM.DD') AS logCreatedAt, TBL.LOG_READ_COUNT AS readCount, TBL.LOG_THUMBNAIL_URL AS thumbnailUrl, TBM.MEMBER_NICKNAME AS memberNickname, TBM.MEMBER_PROFILE_IMAGE_URL AS memberProfileImageUrl, TBC.CATEGORY_NAME AS categoryName, (SELECT COUNT(*) FROM TBL_LOG_LIKE TBL_LIKE WHERE TBL_LIKE.LOG_ID = TBL.ID) AS likeCount FROM TBL_LOG TBL JOIN TBL_MEMBER TBM ON TBL.MEMBER_ID = TBM.ID JOIN TBL_CATEGORY TBC ON TBL.CATEGORY_ID = TBC.ID WHERE TBC.CATEGORY_NAME = #{category}
ORDER BY likeCount DESC ORDER BY TBL.LOG_READ_COUNT DESC ORDER BY TBL.LOG_CREATE_AT DESC
OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY
